<?php get_header(); ?><main class="zole-page-content"><div class="container"><h1 class="entry-title mb-5"><?php the_archive_title(); ?></h1><div class="row g-4"><?php if(have_posts()): while(have_posts()): the_post(); ?><div class="col-md-6 col-lg-4"><article class="zole-card"><h2 class="h4"><a href="<?php the_permalink(); ?>"><?php the_title(); ?></a></h2><p><?php echo esc_html(wp_trim_words(get_the_excerpt(), 24)); ?></p></article></div><?php endwhile; endif; ?></div><?php the_posts_pagination(); ?></div></main><?php get_footer(); ?>